const Q_ECONOMICS_2015=[{"id": "objective>Economics>2015>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major implication of high dependency ratio on an economy is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">high capital information </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vicious circle of poverty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">low cost of living </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high standard of living </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">High dependency ratio is often associated with a country having large percentage of its population as aged and youths. This will tend to aggravate poverty in the economy.</div>", "topic": "ECONOMIC DEVELOPMENT : INDICATORS OF GROWTH & DEVELOPMENT"}, {"id": "objective>Economics>2015>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major problems of the agricultural sector in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low literacy level of farmers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">small size of farms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pest attach on crops </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate modern farm implements</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Use of Crude implements is often related to agricultural sector in Nigeria and is a major impediment to agricultural productivity.</div>", "topic": "AGRICULTURE IN WEST AFRICA : INTRODUCTION"}, {"id": "objective>Economics>2015>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cooperative societies are characterized with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">divergent interest of members </div>", "<div style=\"font-family:Cambria;font-size:17px;\">limited liability </div>", "<div style=\"font-family:Cambria;font-size:17px;\">free entry and exist </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unlimited size of membership </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cooperative societies are characterized by limited liability. This means that the financial liability of the members of the cooperative is limited to the amount they have invested in the cooperative. This is a key characteristic of cooperative societies because it protects the personal assets of the members from being used to pay off the debts of the cooperative. This encourages people to join cooperatives because they know that their personal assets are not at risk.</div>", "topic": "BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES"}, {"id": "objective>Economics>2015>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal propensity to save measures the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ratio of change in saving to change in income.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">change of supply as a result of a change in consumption. </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ratio of change in consumption to a change in the level of income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">average propensity to consume </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The marginal propensity to save (MPS) is an economic concept that shows the proportion of an aggregate raise in pay that a consumer spends on saving rather than on the consumption of goods and services. It is calculated as the change in saving divided by the change in income. Therefore, the correct answer is the ratio of change in saving to change in income.</div>", "topic": "EQUILIBRIUM LEVEL OF NATIONAL INCOME : SAVINGS FUNCTION"}, {"id": "objective>Economics>2015>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Structural unemployment is mainly caused by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a change in the consumption pattern </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a change in the business circle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in the output level </div>", "<div style=\"font-family:Cambria;font-size:17px;\">seasonal variation </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Structural Unemployment is often associated with changes in consumption or demand patterns in an economy leading to changes in industrial structures.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2015>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major problems of census in Nigeria is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">inadequate skilled personnel </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high dependency ratio </div>", "<div style=\"font-family:Cambria;font-size:17px;\">distortion of census figures </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high cost of conducting census </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">High cost of conducting census is the major reasons why census was abandoned which is a major problem to Nigeria.</div>", "topic": "POPULATION : INTRODUCTION"}, {"id": "objective>Economics>2015>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A decrease in government expenditure in an economy will cause general price level to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">remain constant </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluctuate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fall</div>", "<div style=\"font-family:Cambria;font-size:17px;\">rise </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When government reduces expenditure (fiscal policy) it has the effect of causing prices to fall as demand will be low.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2015>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/>  <br/> from the above, find the value of K and F respectively</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">13 and 27 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">27 and 13 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10 and 27 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">27 and 10 </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">TP (K) = AP x Unit of labour <br/>                   = 9 x 3 <br/>                       = 27 <br/>  <br/> MP = ∆TP/ ∆Q <br/>              = 40 -27 / 4 - 3 <br/>                     = 13</div>", "topic": "THEORY OF PRODUCTION : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2015>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of consumer behaviour, the sum of all marginal utilities is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">average marginal utility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the initial marginal utility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total utility </div>", "<div style=\"font-family:Cambria;font-size:17px;\">diminishing marginal utility </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Marginal</td><td style=\"text-align:center;\">Utility</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">change in total utility<hr size=\"1\" />change in output</td></tr></table></div>  <br/>  Hence, the sum of all marginal utilities gives total utility. <br/>  <br/> Total utility is the aggregate level of satisfaction or fulfillment that a consumer receives through the consumption of a specific good or service. Each individual unit of a good or service has its own marginal utility, and the total utility is simply the sum of all the marginal utilities of the individual units</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2015>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a pure capital economy, the means and factors of production are owned and controlled by the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">public and private sectors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">feudal lords</div>", "<div style=\"font-family:Cambria;font-size:17px;\">public sector </div>", "<div style=\"font-family:Cambria;font-size:17px;\">private sector</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The private sector controls the means of production and distribution as they determine what, how and for whom to produce.</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2015>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A factor earning which is paid out as unemployment benefits is referred to as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">interest rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct taxes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic rent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">transfer payment </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Transfer earning is concerned with factor earning paid from unemployment benefits. It is mostly paid to pensioners.</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2015>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/>  <br/> From the graph above, FG indicates </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equilibrium quantity demanded </div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess supply </div>", "<div style=\"font-family:Cambria;font-size:17px;\">equilibrium quantity supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess demanded </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Excess supply or surplus is represented by FG and it is the point above the equilibrium. It occurs when supply is greater than demand leading to fall in price.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2015>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand for money is referred to as the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">amount of money in fixed deposit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">desire to hold money in tangible assets</div>", "<div style=\"font-family:Cambria;font-size:17px;\">need for money to invest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">desire to hold money in liquid form rather than investing it. </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand for money is willingness to hold money in cash than investing it. Lord keynes called demand for money liqudity preference which simply means the desire to hold cash</div>", "topic": "MONEY : DEMAND FOR MONEY"}, {"id": "objective>Economics>2015>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of production, a producer is at equilibrium at a point where</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isocost is above the isoquant curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">isoquant is below the isocost curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">isocost is tangent to the marginal revenue </div>", "<div style=\"font-family:Cambria;font-size:17px;\">isoquant is tangent to the isocost curve. </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of production, a producer is at equilibrium at a point where the isoquant is tangent to the isocost curve. This is because at this point, the producer is producing at the lowest possible cost. The isoquant curve represents all combinations of inputs that yield the same level of output, while the isocost curve represents all combinations of inputs that cost the same amount. When these two curves are tangent, it means that the producer is using the inputs in the most cost-effective way.</div>", "topic": "THEORY OF PRODUCTION (2) : PRODUCERS EQUILIBRIUM"}, {"id": "objective>Economics>2015>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Balance of trade shows the relationship between the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">internal external trade </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total value of visible import and export </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficit and surplus balance of payments </div>", "<div style=\"font-family:Cambria;font-size:17px;\">total value of invisible import and export  </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The balance of trade shows the relationship between the total value of visible import and export. It is the difference between a country's imports and its exports. Balance of trade is the largest component of a country's balance of payments. Deficit and surplus balance of payments is a broader concept that includes not only trade of goods and services, but also financial transfers. Therefore, the correct answer is the total value of visible import and export.</div>", "topic": "INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT"}, {"id": "objective>Economics>2015>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the cash reserve ratio is 30%, a new deposit of N20 million will increase money supply by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N57.8m </div>", "<div style=\"font-family:Cambria;font-size:17px;\">N47.9m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N69.7m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N66.7m</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The money multiplier is the amount of money that banks generate with each dollar of reserves. The formula for the money multiplier is 1 / Reserve Requirement. In this case, the reserve requirement is 30% or 0.3. So, the money multiplier is 1 / 0.3 = 3.33. Therefore, a new deposit of N20 million will increase the money supply by 3.33 * N20 million = N66.6 million. The closest option to this is N66.7m.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2015>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A fall in the price of ostentatious goods will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the quantity demanded </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the quantity demanded </div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease demand </div>", "<div style=\"font-family:Cambria;font-size:17px;\">increalse demand </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A fall in the price of ostentatious goods or veblen goods, will likely decreases demand, as their appeal as status symbols and exclusive items diminishes when they become more accessible.</div>", "topic": "THE THEORY OF DEMAND : DISTINCTION BETWEEN CHANGE IN QUANTITY DEMANDED AND CHANGE IN DEMAND"}, {"id": "objective>Economics>2015>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Payment of interests on loans and the repayment of capital sum at a future date is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">balance debt </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debt servicing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debt relief </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debt retaking </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Debt servicing relates to the payment of initial capital and interest on loan borrowed. <br/>  <br/> Debt service is the amount of money required over a period of time to repay debts. It includes repayment of: principal and interest. and lease payments (on business vehicles, for example)</div>", "topic": "PUBLIC FINANCE : BUDGET"}, {"id": "objective>Economics>2015>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most difficult measure of central tendency to determine in a grouped data is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">range </div>", "<div style=\"font-family:Cambria;font-size:17px;\">variance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mean </div>", "<div style=\"font-family:Cambria;font-size:17px;\">mode </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mean is the most difficult measure of central tendency to determine in a grouped data because it requires the sum of all the data points and the total number of data points. The mean is calculated by adding up all the numbers and then dividing by the number of numbers. The other measures, range and variance, are easier to calculate as they do not require the sum of all data points.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2015>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Localization of industry is mainly determined by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">diseconomies if sale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">population growth </div>", "<div style=\"font-family:Cambria;font-size:17px;\">division of labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">access to raw materials </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Access to raw materials is crucial in determining the localization of industries e.g In cement manufacturing.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2015>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Geographical distribution of a population is affected by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">low birth rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the availability of skilled manpower </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the availability of agricultural land </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high birth rate </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Land used for the purpose of agriculture will affect the geographical distribution of population as some states are known to be more fertile in agriculture than others. <br/>  <br/> Geographic Factors of Population Distribution. Physical conditions, such as climate (temperature and rainfall), landforms in terms of altitudes, the quality of the soil and the availability of energy and mine resources are the important geographical determinants of population distribution.</div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2015>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The tax burden on a commodity will be shared equally if the demand is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fairly elastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fairly inelastic </div>", "<div style=\"font-family:Cambria;font-size:17px;\">unitary elastic </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The tax burden on a commodity will be shared equally if the demand is unitary elastic. Elasticity of demand measures how much the quantity demanded changes with a change in price. If the demand is unitary elastic, it means that the percentage change in quantity demanded is exactly equal to the percentage change in price. Therefore, if a tax is imposed on a commodity, the burden of the tax will be shared equally between the consumers and the producers.</div>", "topic": "PUBLIC FINANCE : ELASTICITY OF TAX"}, {"id": "objective>Economics>2015>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Higher income taxes can be used to control </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">demand-pull inflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">high interest rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost-push inflation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hyperinflation </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Demand-pull inflation is often associated with increase in aggregates demand without corresponding increase in supply. Hence, taxes can be imposed on goods to control/ cushion the effect of demand-pull inflation.</div>", "topic": "PUBLIC FINANCE : FISCAL POLICY"}, {"id": "objective>Economics>2015>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/>  <br/> From the graph above, a shift of the supply curve from S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">0</span> to S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> will lead to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a decrease in price and quantity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">no change in price and quantity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in price and quantity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in price and increase in quantity </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A shift from S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">o</span> to S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>S<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>, implies an increase in quantity supplied. This resulting effect will be a decline in price and increase in quantity.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2015>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An indifference map is made up of a set of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumer's total utility  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer surplus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget lines </div>", "<div style=\"font-family:Cambria;font-size:17px;\">indifference curves </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An indifference map is made up of a set of indifference curves. An indifference curve is a graph showing combination of goods that gives the consumer equal satisfaction and utility. Each point on an indifference curve indicates that a consumer is indifferent between the two and all points give him the same utility.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : INDIFFERENCE CURVE"}, {"id": "objective>Economics>2015>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Recaptalization policy will enable commercial banks to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">employ more qualified workers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">open more branches </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce interest rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have a very strong capital base </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A policy of recapitalization will help to promote a strong capital base for commercial banks hence reducing the number of liquidating banks.</div>", "topic": "FINANCIAL INSTITUTION : COMMERCIAL BANKS"}, {"id": "objective>Economics>2015>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of persons required to form a private limited company ranges from </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ten to twenty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">two to fifty </div>", "<div style=\"font-family:Cambria;font-size:17px;\">two to seven </div>", "<div style=\"font-family:Cambria;font-size:17px;\">seven to ten </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A private limited company is a type of business entity in which ownership is shared by a small group of people. According to the Companies Act, the minimum number of members to start a private limited company is two and the maximum number is fifty. Therefore, the correct answer is 'two to fifty'.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2015>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The major function of international monetary fund is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provision of short-run loans to medium scale industries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of long-term loans for infrastructure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">development of agriculture in member countries </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maintenance of stable exchange rates </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The International Monetary Fund (IMF) is an international organization that provides financial assistance and advice to member countries. Its primary purpose is to ensure the stability of the international monetary system—the system of exchange rates and international payments that enables countries (and their citizens) to transact with each other. Therefore, the correct answer is 'maintenance of stable exchange rates'.</div>", "topic": "INTERNATIONAL ECONOMIC ORGANISATION : OPEC, ECA, IMF"}, {"id": "objective>Economics>2015>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major activities in the upstream sector of the Nigeria petroleum industry includes </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">transportation of finished products </div>", "<div style=\"font-family:Cambria;font-size:17px;\">refining of crude oil </div>", "<div style=\"font-family:Cambria;font-size:17px;\">marketing of refine petrol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exploration crude oil </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The upstream sector of the petroleum industry refers to the searching for potential underground or underwater crude oil and natural gas fields, drilling of exploratory wells, and subsequently drilling and operating the wells that recover and bring the crude oil or raw natural gas to the surface. Therefore, the correct answer is 'exploration of crude oil'.</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : ONSHORE & OFFSHORE OF THE OIL SECTOR"}, {"id": "objective>Economics>2015>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The law of supply states that the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">higher the price the higher the quantity supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">quantity supplied is always equal to the quantity demanded </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lower the price the higher the quantity supplied </div>", "<div style=\"font-family:Cambria;font-size:17px;\">higher the price the lower the quantity supplied </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of supply is a fundamental principle in economics that states that, assuming all else being equal, an increase in the price of goods will have a direct relationship with the quantity of the goods produced by producers. In other words, the higher the price, the higher the quantity supplied. Producers supply more at a higher price because selling a higher quantity at a higher price increases revenue.</div>", "topic": "THEORY OF SUPPLY : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2015>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the features of a perfect competitive firm is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">restrictions to entry and exit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price discrimination </div>", "<div style=\"font-family:Cambria;font-size:17px;\">absence of transportation cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">product differentiation </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In perfect market, there is no transport cost due to the mobility of factors of production and free entry and exit.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2015>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basis for international trade is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">difference in natural resources endowment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">difference in the population size </div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevailing interest rate on multilateral loans </div>", "<div style=\"font-family:Cambria;font-size:17px;\">economic system in practice </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The basis for international trade is the difference in natural resources endowment. Countries trade with each other when they have a surplus of the resources that are in demand by other countries. Natural resources endowment refers to the naturally occurring assets including mineral deposits, soil fertility, climatic conditions favorable for agriculture, and other factors. Countries with abundant natural resources export them to countries with less. This forms the basis for international trade.</div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2015>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Training farmers on the improved farming techniques is the major activity of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">intermediate workers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">middlemen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">extension workers </div>", "<div style=\"font-family:Cambria;font-size:17px;\">creditors </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Extension workers are professionals who work in the agricultural sector to provide training, resources, and advice to farmers. They play a crucial role in educating farmers about improved farming techniques, new technologies, and sustainable farming practices. Therefore, training farmers on improved farming techniques is a major activity of extension workers.</div>", "topic": "AGRICULTURE IN WEST AFRICA : ROLES"}, {"id": "objective>Economics>2015>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a free market economy, prices are determined by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the central government </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the forces of demand and supply </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a free market economy, prices are determined by the forces of demand and supply. This is because a free market economy is an economic system where decisions regarding investment, production, and distribution are guided by the price signals created by the forces of supply and demand. The central government does not interfere in setting prices, and neither do consumers or producers individually. They all respond to the price signals in the market.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : DETERMINANTS OF PRICE UNDER FREE MARKET"}, {"id": "objective>Economics>2015>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The basic economic problem of what to produce in an economy is determined by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the availability of labour </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the means of distribution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the availability of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">technological know-how </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">What to produce is mostly affected by the availability of resources in the economy as no producer or economy can think of producing without first counting the cost.</div>", "topic": "INTRODUCTION TO ECONOMICS : BASIC CONCEPT OF ECONOMICS"}, {"id": "objective>Economics>2015>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In Nigeria, a fall in supply of petrol would generally affect the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">import of goods and services </div>", "<div style=\"font-family:Cambria;font-size:17px;\">export of goods and services </div>", "<div style=\"font-family:Cambria;font-size:17px;\">general price level in the country </div>", "<div style=\"font-family:Cambria;font-size:17px;\">exchange rate of the naira </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A fall in petrol supply, will mean no hoarding and black marketing which will help to reduce the price of goods in the market generally.</div>", "topic": "INFLATION & DEFLATION : EFFECT"}, {"id": "objective>Economics>2015>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The short-run equilibrium point of a perfectly competitive firm is attained at a point where </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">price is equal to total cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the demand curve is tangential to the marginal cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the marginal cost curve is equal to the marginal revenue curve </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the marginal cost is equal to the price of the sum </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the short-run equilibrium of a perfectly competitive firm, the firm's marginal cost (MC) is equal to its marginal revenue (MR). This is because, in perfect competition, firms are price takers and can sell as much output as they want at the market price. Therefore, they will produce up to the point where the cost of producing an additional unit (MC) is equal to the revenue gained from selling that additional unit (MR).</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2015>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Government can protect consumers from exploitative prices by introducing </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">minimum price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price differentiation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">price floor </div>", "<div style=\"font-family:Cambria;font-size:17px;\">maximum price </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">By maximum price, the commodities are sold below the equilibrium price and there will be excess demand over supply</div>", "topic": "THE THEORY OF PRICE DETERMINATION : PRICE LEGISLATION"}, {"id": "objective>Economics>2015>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a fall in the price of commodity K brought about an increase in the demand for commodity Y, the two commodities are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">composites </div>", "<div style=\"font-family:Cambria;font-size:17px;\">derived in nature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">substitutes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">complements </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Complementary demand is generated for a product as a result of demand for a related but different product e.g computers and software, vehicles and tyres etc. It is also known as joint demand.</div>", "topic": "THE THEORY OF DEMAND : TYPES OF DEMAND"}, {"id": "objective>Economics>2015>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of production, the price of a factor inputs is determined by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the prevailing exchange rate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">its elasticity of demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the existence of large market </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the prevailing interest </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the theory of production, the price of a factor inputs is determined by its elasticity of demand. Elasticity of demand refers to the degree of responsiveness of quantity demanded to a change in the price of the factor input. If the demand for a factor input is elastic, a small change in price will result in a large change in quantity demanded. Conversely, if the demand for a factor input is inelastic, a change in price will result in a small change in quantity demanded.</div>", "topic": "THEORY OF PRODUCTION (1) : FACTORS OF PRODUCTION"}, {"id": "objective>Economics>2015>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/>  <br/> From the graph above, find the modal score.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100</div>", "<div style=\"font-family:Cambria;font-size:17px;\">60</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mode is the mark with the highest frequency i.e 60.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2015>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When the selling price of a monopolist is below his short-run marginal cost, he is said to be making </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an economic profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">losses </div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">supernormal profit </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In economics, when a monopolist's selling price is below his short-run marginal cost, it means that the cost of producing an additional unit of output is more than the price at which it is sold. This implies that the monopolist is making losses. Therefore, the correct answer is 'losses'.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2015>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The overall economic performance of a country can be assessed through </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">overlooking of its agriculture sector </div>", "<div style=\"font-family:Cambria;font-size:17px;\">employment estimates </div>", "<div style=\"font-family:Cambria;font-size:17px;\">national income estimates  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance of payments </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The overall economic performance of a country is best assessed through its national income estimates. National income estimates provide a comprehensive measure of a nation's overall economic activity. It includes the total income earned by a nation's people, including wages, rents, interest, and profits. It is a broad measure that reflects the total economic output of a country, and thus, it is a good indicator of economic performance.</div>", "topic": "NATIONAL INCOME : CONCEPT"}, {"id": "objective>Economics>2015>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The supply of agricultural products is mainly determined by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">consumer's taste </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumer's income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">technology </div>", "<div style=\"font-family:Cambria;font-size:17px;\">consumers </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The supply of agricultural products is mainly determined by technology. Technology in agriculture involves the use of machinery and other advanced techniques to increase the efficiency and output of agricultural processes. It does not depend on consumer's taste, income or consumers themselves as these factors are more related to the demand side of the market.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2015>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Determine the median of 6, 10, 5, 12, 20, 18, 20 and 4. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">11</div>", "<div style=\"font-family:Cambria;font-size:17px;\">67</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.56</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12 </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">(set of numbers = 6, 10, 5, 12, 20 18, 20, 4) <br/>  <br/>  <br/> Arrange the numbers in ascending order <br/>  <br/>  <br/> 4, 5, 6, 10, 12, 18, 20, 20 <br/>  <br/>  <br/> median of these numbers are = 10 and 12 <br/>  <br/>  <br/> 10 + 12/2 = 11</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2015>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/>  <br/> From the table above, find the range of the distribution </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11</div>", "<div style=\"font-family:Cambria;font-size:17px;\">70</div>", "<div style=\"font-family:Cambria;font-size:17px;\">59</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Range = Highest value - Lowest value <br/>  = 70 - 11 <br/>  = 59</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2015>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The failure of the Nigeria industrial sector is mainly associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">lack of raw materials </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate market for industrial goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">underdeveloped infrastructural facilities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate capital </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The failure of the Nigeria industrial sector is mainly associated with underdeveloped infrastructural facilities. Infrastructure is the backbone of any country's economic development. It is an umbrella term that includes physical structures, systems, and facilities needed for the operation of a society or enterprise. In the context of an industrial sector, infrastructure refers to facilities and systems that support manufacturing and production, such as transportation, electricity, water supply, and telecommunications. Without well-developed infrastructure, industries cannot operate efficiently, leading to their failure.</div>", "topic": "INDUSTRY & INDUSTRIALISATION : INTRODUCTION"}, {"id": "objective>Economics>2015>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If Qd = 40-4P and P = N4, what is the quantity demanded? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">30</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">24</div>", "<div style=\"font-family:Cambria;font-size:17px;\">26 </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Qd = 40 - 4P  <br/>  P = ₦4  <br/>  = 40 - 4(4)  <br/>  = 40 - 16 <br/>  = 24.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2015>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The long-run total cost curve shows the cost of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all fixed factors of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the average fixed cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all factors inputs that are employed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">variable factors of production </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The long-run total cost curve shows the cost of all factor inputs that are employed. In the long run, all factors of production are variable, and firms adjust all types of inputs to achieve the lowest total cost. Therefore, the long-run total cost curve represents the cost of all factor inputs that are employed.</div>", "topic": "THE CONCEPT OF COST & REVENUE : SHORT RUN & LONG RUN COST"}, {"id": "objective>Economics>2015>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The implementation of developmental plans in Nigeria is hampered by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shortage of funds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shortage of skilled manpower</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inadequate technology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor government commitment</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Poor government commitment is particularly crucial. The commitment and dedication of the government to implementing and following through on developmental plans and policies are vital for success. Lack of commitment can lead to delays, inconsistencies, and a lack of accountability, ultimately hindering progress and undermining the effectiveness of developmental initiatives.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}];
